parameters.jsCode:
// Extrai e parseia a resposta do Gemini
const response = $input.item.json.candidates[0].content.parts[0].text;

// Remove markdown se houver
const jsonText = response.replace(/```json\n?|```/g, '').trim();

let dadosCliente;
try {
  dadosCliente = JSON.parse(jsonText);
} catch (error) {
  dadosCliente = {
    nome: null,
    telefone: null,
    email: null,
    servico: null,
    localizacao: null,
    deseja_agendamento: false,
    urgencia: "média",
    observacoes: "Erro ao processar resposta da IA",
    campos_faltantes: ["nome", "telefone", "email"]
  };
}

// Adiciona dados da sessão
dadosCliente.session_id = $('Normalizar_Entrada').item.json.session_id;
dadosCliente.timestamp = $('Normalizar_Entrada').item.json.timestamp;
dadosCliente.mensagem_original = $('Normalizar_Entrada').item.json.mensagem_usuario;

return { json: dadosCliente };

// Validação de telefone
const dados = $input.item.json;
let telefone = dados.telefone;

if (!telefone) {
  return {
    json: {
      ...dados,
      telefone_valido: false,
      mensagem_erro: "Por favor, informe seu telefone com DDD para continuarmos."
    }
  };
}

// Remove caracteres não numéricos
telefone = telefone.replace(/\D/g, '');

// Verifica se tem 10 ou 11 dígitos (DDD + número)
const telefoneValido = telefone.length >= 10 && telefone.length <= 11;

if (!telefoneValido) {
  return {
    json: {
      ...dados,
      telefone_valido: false,
      mensagem_erro: "O telefone informado parece estar incorreto. Por favor, informe com DDD (ex: 11987654321)"
    }
  };
}

return {
  json: {
    ...dados,
    telefone: telefone,
    telefone_valido: true
  }
};

// Validação de e-mail
const dados = $input.item.json;
const email = dados.email;

if (!email) {
  return {
    json: {
      ...dados,
      email_valido: false,
      mensagem_erro: "Por favor, informe seu e-mail para enviarmos as informações."
    }
  };
}

// Regex básica para validação de e-mail
const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
const emailValido = emailRegex.test(email);

if (!emailValido) {
  return {
    json: {
      ...dados,
      email_valido: false,
      mensagem_erro: "O e-mail informado parece estar incorreto. Por favor, verifique e informe novamente."
    }
  };
}

return {
  json: {
    ...dados,
    email_valido: true
  }
};

